// webhookProxy.js

const filterHeaders = (headers = {}) => {
  const filtered = {};
  for (const k in headers) {
    if (!/^host$/i.test(k)) filtered[k] = headers[k];
  }
  return filtered;
};

const doFetch = async ({ method, url, headers, body }) => {
  const opts = { method, headers: filterHeaders(headers) };
  if (body && !['GET', 'HEAD'].includes(method)) opts.body = body;

  const resp = await fetch(url, opts);

  const resHeaders = {};
  resp.headers.forEach((v, k) => (resHeaders[k] = v));

  const buffer = Buffer.from(await resp.arrayBuffer());
  const isBinary = !/^(text\/|application\/json)/i.test(resHeaders['content-type'] || '');
  const responseBody = buffer.toString(isBinary ? 'base64' : 'utf8');

  return { status: resp.status, headers: resHeaders, body: responseBody, isBinary };
};

// AWS Lambda
exports.handler = async (event) => {
  try {
    const method = event.httpMethod || 'GET';
    const rawBody = event.body
      ? Buffer.from(event.body, event.isBase64Encoded ? 'base64' : 'utf8')
      : undefined;

    const url =
      event.queryStringParameters?.url ||
      (event.body && !event.isBase64Encoded && JSON.parse(event.body).url);

    if (!url) return { statusCode: 400, body: 'Missing url parameter' };

    const { status, headers, body, isBinary } = await doFetch({
      method,
      url,
      headers: event.headers || {},
      body: rawBody,
    });

    return {
      statusCode: status,
      headers: { ...headers, 'Access-Control-Allow-Origin': '*' },
      body,
      isBase64Encoded: isBinary,
    };
  } catch (err) {
    return { statusCode: 500, body: err.message };
  }
};

// GCP Cloud Function (HTTP)
exports.webhookProxy = async (req, res) => {
  try {
    const url = req.query.url || req.body?.url;

    if (!url) {
      res.status(400).send('Missing url parameter');
      return;
    }

    const rawBody =
      req.rawBody ||
      (typeof req.body === 'string' ? req.body : JSON.stringify(req.body || {}));

    const { status, headers, body, isBinary } = await doFetch({
      method: req.method,
      url,
      headers: req.headers,
      body: rawBody,
    });

    for (const k in headers) res.setHeader(k, headers[k]);
    res.setHeader('Access-Control-Allow-Origin', '*');

    if (isBinary) {
      res.status(status).send(Buffer.from(body, 'base64'));
    } else {
      res.status(status).send(body);
    }
  } catch (err) {
    res.status(500).send(err.message);
  }
};